/**
 * Complete a level
 * POST /levels/complete
 * Body:
 * {
 *   "playerId": "p1",
 *   "levelId": "12",
 *   "score": 850,
 *   "timeMs": 54000
 * }
 */
app.post('/levels/complete', (req, res) => {
  const { playerId, levelId } = req.body || {};
  let { score, timeMs } = req.body || {};

  if (!isNonEmptyString(playerId, 64)) return res.status(400).json({ error: 'Invalid playerId' });
  if (!isNonEmptyString(levelId, 64)) return res.status(400).json({ error: 'Invalid levelId' });

  ensurePlayer(playerId);

  score = clampInt(score, 0, 2000000, 0);
  timeMs = clampInt(timeMs, 0, 24 * 60 * 60 * 1000, 0);

  const completionKey = `${playerId}:${levelId}`;
  const prev = db.levelCompletions.get(completionKey);

  // Keep best score / best time depending on your design; here we store latest and track bests
  const completion = {
    playerId,
    levelId,
    score,
    timeMs,
    completedAt: nowIso(),
    bestScore: prev ? Math.max(prev.bestScore, score) : score,
    bestTimeMs: prev ? Math.min(prev.bestTimeMs, timeMs || prev.bestTimeMs) : timeMs,
    attempts: prev ? prev.attempts + 1 : 1,
  };

  db.levelCompletions.set(completionKey, completion);

  // Create a reward claim token per completion submission (idempotency not implemented)
  const rewards = calculateRewards({ levelId, score, timeMs });
  const rewardId = makeRewardId();

  db.rewardLedger.set(rewardId, {
    rewardId,
    playerId,
    levelId,
    rewards,
    createdAt: nowIso(),
    claimedAt: null,
    source: { score, timeMs },
  });

  res.json({
    ok: true,
    completion,
    reward: {
      rewardId,
      preview: rewards,
      claimEndpoint: '/rewards/claim',
    },
  });
});

/**
 * Claim a reward
 * POST /rewards/claim
 * Body:
 * {
 *   "playerId": "p1",
 *   "rewardId": "rw_..."
 * }
 */
app.post('/rewards/claim', (req, res) => {
  const { playerId, rewardId } = req.body || {};
  if (!isNonEmptyString(playerId, 64)) return res.status(400).json({ error: 'Invalid playerId' });
  if (!isNonEmptyString(rewardId, 128)) return res.status(400).json({ error: 'Invalid rewardId' });

  ensurePlayer(playerId);

  const entry = db.rewardLedger.get(rewardId);
  if (!entry) return res.status(404).json({ error: 'Reward not found' });
  if (entry.playerId !== playerId) return res.status(403).json({ error: 'Reward does not belong to player' });

  if (entry.claimedAt) {
    return res.json({
      ok: true,
      alreadyClaimed: true,
      rewardId,
      claimedAt: entry.claimedAt,
      inventory: db.playerInventory.get(playerId),
    });
  }

  entry.claimedAt = nowIso();
  db.rewardLedger.set(rewardId, entry);

  const inventory = addToInventory(playerId, entry.rewards);

  res.json({
    ok: true,
    rewardId,
    claimedAt: entry.claimedAt,
    granted: entry.rewards,
    inventory,
  });
});

